impl PetersonMutex {
    /// TypeOK ==
    ///     /\ pc \in [Procs -> {"idle", "set_flag", "set_turn", "wait", "critical"}]
    ///     /\ flag \in [Procs -> {TRUE, FALSE}]
    ///     /\ turn \in {0, 1}
    fn check_type_ok(state: &PetersonMutexState) -> bool {
        let valid_pcs = tla_set![
            "idle".to_string(),
            "set_flag".to_string(),
            "set_turn".to_string(),
            "wait".to_string(),
            "critical".to_string()
        ];
        let pc_ok = Self::procs()
            .iter()
            .all(|p| state.pc.apply(p).map_or(false, |v| valid_pcs.contains(v)));

        let flag_ok = Self::procs()
            .iter()
            .all(|p| state.flag.apply(p).is_some());

        let turn_ok = state.turn == 0 || state.turn == 1;

        pc_ok && flag_ok && turn_ok
    }

    /// MutualExclusion ==
    ///     ~ (pc[0] = "critical" /\ pc[1] = "critical")
    fn check_mutual_exclusion(state: &PetersonMutexState) -> bool {
        let p0_critical = state.pc.apply(&0).map(|s| s == "critical").unwrap_or(false);
        let p1_critical = state.pc.apply(&1).map(|s| s == "critical").unwrap_or(false);
        !(p0_critical && p1_critical)
    }
}

