    use super::*;

    /// Every initial state satisfies both invariants.
    #[test]
    fn test_init_satisfies_invariants() {
        let sm = PetersonMutex;
        let init_states = sm.init();
        assert_eq!(init_states.len(), 1, "Peterson's has exactly one initial state");

        for state in &init_states {
            assert!(
                PetersonMutex::check_type_ok(state),
                "TypeOK violated in init state: {:?}",
                state
            );
            assert!(
                PetersonMutex::check_mutual_exclusion(state),
                "MutualExclusion violated in init state: {:?}",
                state
            );
        }
    }

    /// Inductive check: for every reachable state, every successor also
    /// satisfies all invariants.
    #[test]
    fn test_next_preserves_invariants() {
        let sm = PetersonMutex;
        let all_states = collect_states(&sm, 100);

        for state in &all_states {
            let successors = sm.next(state);
            for succ in &successors {
                assert!(
                    PetersonMutex::check_type_ok(succ),
                    "TypeOK violated after transition from {:?}",
                    state
                );
                assert!(
                    PetersonMutex::check_mutual_exclusion(succ),
                    "MutualExclusion violated after transition from {:?} to {:?}",
                    state,
                    succ
                );
            }
        }
    }

