    /// Verify the algorithm's core mechanism: when both processes contend,
    /// the one that defers (sets turn) last will wait, ensuring the other
    /// enters first.
    #[test]
    fn test_peterson_correctness() {
        let sm = PetersonMutex;

        // Start from the initial state
        let init = &sm.init()[0];
        assert_eq!(init.pc.apply(&0).unwrap(), "idle");
        assert_eq!(init.pc.apply(&1).unwrap(), "idle");
        assert_eq!(init.flag.apply(&0).unwrap(), &false);
        assert_eq!(init.flag.apply(&1).unwrap(), &false);
        assert_eq!(init.turn, 0);

        // Process 0 sets flag
        let after_p0_flag = sm
            .next(init)
            .into_iter()
            .find(|s| {
                s.pc.apply(&0).map(|v| v == "set_flag").unwrap_or(false)
                    && s.pc.apply(&1).map(|v| v == "idle").unwrap_or(false)
            })
            .expect("p0 should be able to set flag from idle");

        assert_eq!(after_p0_flag.flag.apply(&0).unwrap(), &true);

        // Process 0 sets turn to 1 (defers)
        let after_p0_turn = sm
            .next(&after_p0_flag)
            .into_iter()
            .find(|s| {
                s.pc.apply(&0).map(|v| v == "set_turn").unwrap_or(false) && s.turn == 1
            })
            .expect("p0 should be able to set turn");

        // Process 0 enters wait
        let after_p0_wait = sm
            .next(&after_p0_turn)
            .into_iter()
            .find(|s| s.pc.apply(&0).map(|v| v == "wait").unwrap_or(false))
            .expect("p0 should be able to enter wait");

        // Since p1's flag is false, p0 can enter critical section
        let after_p0_enter = sm
            .next(&after_p0_wait)
            .into_iter()
            .find(|s| s.pc.apply(&0).map(|v| v == "critical").unwrap_or(false))
            .expect("p0 should enter critical (p1 flag is false)");

        assert_eq!(after_p0_enter.pc.apply(&0).unwrap(), "critical");
        // Mutual exclusion: p1 is not critical
        assert_ne!(after_p0_enter.pc.apply(&1).unwrap(), "critical");
    }

